public class CSVFormatTest {

    @Test
    public void testIsEscapeCharacterSet() throws NoSuchMethodException, IllegalAccessException, InvocationTargetException, InstantiationException {
        // Given
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class, Character.class, Character.class,
                boolean.class, boolean.class, String.class, String.class,
                Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat csvFormat = constructor.newInstance(',', '"', null, '#', '\\', true, false, "\r\n", "\\N",
                new Object[]{"Header1", "Header2"}, new String[]{"Comment1", "Comment2"}, true, false, true, true, false);

        // When
        boolean isEscapeCharacterSet = csvFormat.isEscapeCharacterSet();

        // Then
        assertTrue(isEscapeCharacterSet);
    }

